import React, { useState, useEffect } from 'react';
import axios from 'axios';
import RegisterComplaint from './pages/RegisterComplaint';

function App() {
  // 1. State define ki hai complaints store karne ke liye
  const [complaints, setComplaints] = useState([]);

  // 2. Backend se data fetch karne ka function
  const fetchComplaints = async () => {
    try {
      const response = await axios.get('http://127.0.0.1:8000/api/complaints/');
      setComplaints(response.data);
    } catch (err) {
      console.error("Backend se connect nahi ho pa raha", err);
    }
  };

  // 3. Page load hote hi data fetch karein
  useEffect(() => {
    fetchComplaints();
  }, []);

  // 4. Status update (Resolve) karne ka function
  const handleResolve = async (id) => {
    try {
      await axios.put(`http://127.0.0.1:8000/api/complaints/${id}/resolve`);
      alert("Status Updated Successfully!");
      fetchComplaints(); // Bina page refresh kiye data update karne ke liye
    } catch (err) {
      console.error("Update fail ho gaya", err);
      alert("Error: Status update nahi ho paya");
    }
  };

  return (
    <div style={{ padding: '20px', fontFamily: 'Arial', maxWidth: '800px', margin: '0 auto' }}>
      <h1 style={{ color: '#2c3e50', textAlign: 'center' }}>Digital Grievance Redressal System</h1>
      <hr />
      
      {/* Nayi complaint register karne ka form */}
      <RegisterComplaint onRefresh={fetchComplaints} />

      <div style={{ marginTop: '30px' }}>
        <h3>Registered Complaints:</h3>
        {complaints.length === 0 ? (
          <p style={{ color: 'gray' }}>No complaints found (Check if Backend is running).</p>
        ) : (
          <ul style={{ listStyleType: 'none', padding: 0 }}>
            {complaints.map((c) => (
              <li key={c.id} style={{ 
                padding: '15px', 
                borderBottom: '1px solid #ddd', 
                backgroundColor: '#f9f9f9',
                marginBottom: '10px',
                borderRadius: '5px'
              }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                  <div>
                    <b style={{ fontSize: '18px' }}>{c.title}</b> <br />
                    <small style={{ color: '#555' }}>Category: {c.category}</small>
                  </div>
                  
                  <div>
                    <span style={{ 
                      color: c.status === 'Pending' ? 'orange' : 'green', 
                      fontWeight: 'bold',
                      marginRight: '15px'
                    }}> 
                      {c.status} 
                    </span>

                    {c.status === 'Pending' && (
                      <button 
                        onClick={() => handleResolve(c.id)} 
                        style={{ 
                          padding: '5px 10px', 
                          backgroundColor: '#2ecc71', 
                          color: 'white', 
                          border: 'none', 
                          borderRadius: '3px',
                          cursor: 'pointer' 
                        }}
                      >
                        Mark as Resolved
                      </button>
                    )}
                  </div>
                </div>
                <p style={{ marginTop: '10px', color: '#333' }}>{c.description}</p>
              </li>
            ))}
          </ul>
        )}
      </div>
    </div>
  );
}

export default App;
